-- Medieval, Renaissance, and Early Modern Patronage Catalog
-- Portable SQLite database seed for research tracking and future card/DLC generation.
--
-- Build:
--   sqlite3 docs/research/patronage_catalog.sqlite ".read docs/research/patronage_catalog.sql"

PRAGMA foreign_keys = ON;

DROP VIEW IF EXISTS v_card_candidates;
DROP VIEW IF EXISTS v_relationship_prompts;
DROP TABLE IF EXISTS research_tasks;
DROP TABLE IF EXISTS patron_relationships;
DROP TABLE IF EXISTS patron_sources;
DROP TABLE IF EXISTS patrons;
DROP TABLE IF EXISTS sources;

CREATE TABLE patrons (
  id TEXT PRIMARY KEY,
  display_name TEXT NOT NULL,
  sort_name TEXT NOT NULL,
  alt_names TEXT,
  dynasty_house TEXT,
  gender TEXT,
  life_dates TEXT,
  active_start INTEGER,
  active_end INTEGER,
  period_tags TEXT NOT NULL,
  geography TEXT NOT NULL,
  centers TEXT,
  patron_type TEXT NOT NULL,
  domain_tags TEXT NOT NULL,
  documentation_level TEXT NOT NULL CHECK (documentation_level IN ('high','medium','needs review')),
  significance_tier INTEGER NOT NULL CHECK (significance_tier BETWEEN 1 AND 4),
  suggested_glyphs TEXT,
  alchemical_read TEXT,
  summary TEXT NOT NULL,
  game_hooks TEXT,
  catalog_status TEXT NOT NULL DEFAULT 'candidate' CHECK (catalog_status IN ('candidate','sourced','thick-entry','carded','deferred')),
  research_priority TEXT NOT NULL DEFAULT 'medium' CHECK (research_priority IN ('critical','high','medium','low')),
  source_starter TEXT,
  notes TEXT
);

CREATE TABLE sources (
  id TEXT PRIMARY KEY,
  label TEXT NOT NULL,
  url TEXT,
  source_type TEXT NOT NULL,
  notes TEXT
);

CREATE TABLE patron_sources (
  patron_id TEXT NOT NULL REFERENCES patrons(id) ON DELETE CASCADE,
  source_id TEXT NOT NULL REFERENCES sources(id) ON DELETE CASCADE,
  source_note TEXT,
  PRIMARY KEY (patron_id, source_id)
);

CREATE TABLE patron_relationships (
  id TEXT PRIMARY KEY,
  patron_id TEXT NOT NULL REFERENCES patrons(id) ON DELETE CASCADE,
  related_name TEXT NOT NULL,
  related_type TEXT NOT NULL CHECK (related_type IN ('artist','architect','writer','philosopher','scientist','translator','musician','craftsperson','printer','agent','workshop','institution','other')),
  related_role TEXT,
  relationship_type TEXT NOT NULL,
  support_material TEXT,
  works_or_projects TEXT,
  relationship_dynamics TEXT NOT NULL,
  evidence_note TEXT NOT NULL,
  game_mechanic_hook TEXT NOT NULL,
  suggested_board_relation TEXT,
  confidence TEXT NOT NULL DEFAULT 'high' CHECK (confidence IN ('high','medium','needs review')),
  source_refs TEXT NOT NULL,
  notes TEXT
);

CREATE TABLE research_tasks (
  id INTEGER PRIMARY KEY AUTOINCREMENT,
  patron_id TEXT NOT NULL REFERENCES patrons(id) ON DELETE CASCADE,
  task TEXT NOT NULL,
  status TEXT NOT NULL DEFAULT 'todo' CHECK (status IN ('todo','doing','done','blocked')),
  notes TEXT
);

CREATE VIEW v_card_candidates AS
SELECT
  id,
  display_name,
  life_dates,
  geography,
  domain_tags,
  suggested_glyphs,
  significance_tier,
  documentation_level,
  research_priority,
  catalog_status,
  summary
FROM patrons
WHERE catalog_status IN ('candidate','sourced','thick-entry')
ORDER BY significance_tier, research_priority, sort_name;

CREATE VIEW v_relationship_prompts AS
SELECT
  r.id,
  p.display_name AS patron,
  r.related_name,
  r.related_type,
  r.relationship_type,
  r.works_or_projects,
  r.relationship_dynamics,
  r.game_mechanic_hook,
  r.suggested_board_relation,
  r.confidence,
  r.source_refs
FROM patron_relationships r
JOIN patrons p ON p.id = r.patron_id
ORDER BY p.sort_name, r.related_name;

