('galileo-project', 'The Galileo Project: Patrons', 'https://galileo.library.rice.edu/gal/medici.html', 'academic reference', 'Useful for Galileo, Medici, and court science.'),
('italian-renaissance-resources', 'Italian Renaissance Learning Resources', 'https://www.italianrenaissanceresources.com/', 'teaching/reference', 'Strong starter for Italian court patronage, studioli, collecting, and commissions.'),
('loc', 'Library of Congress', 'https://www.loc.gov/', 'library reference', 'Useful for manuscript and astronomy records such as the Alfonsine Tables.'),
('ismi', 'Islamic Scientific Manuscripts Initiative', 'https://ismi.mpiwg-berlin.mpg.de/', 'academic database', 'Useful for medieval Islamic and Iberian scientific patronage.'),
('alfa', 'ALFA: Shaping a European Scientific Scene', 'https://alfa.obspm.fr/', 'research project', 'Alfonsine astronomy and late medieval astronomical transmission.'),
('nga-ngv-smarthistory', 'Smarthistory / museum teaching corpus', 'https://smarthistory.org/', 'teaching/reference', 'Useful starter source for Renaissance patronage and object contexts.'),
('oxford-grove-benezit', 'Oxford Art Online / Grove / Benezit', NULL, 'reference work', 'Subscription reference; add exact article citations during thick-entry pass.'),
('cambridge-histories', 'Cambridge Histories and Companions', NULL, 'scholarly synthesis', 'Use for source expansion, especially science, music, Islamic, and early modern court culture.'),
('specialist-monographs', 'Specialist monographs and catalogues', NULL, 'book/catalogue', 'Placeholder for patron-specific scholarship.');

INSERT INTO patrons (
  id, display_name, sort_name, alt_names, dynasty_house, gender, life_dates,
  active_start, active_end, period_tags, geography, centers, patron_type,
  domain_tags, documentation_level, significance_tier, suggested_glyphs,
  alchemical_read, summary, game_hooks, catalog_status, research_priority, source_starter, notes
) VALUES
('patron-charlemagne', 'Charlemagne', 'Charlemagne', 'Charles the Great', 'Carolingian', 'male', '747-814; r. 768-814', 768, 814, 'early medieval,Carolingian', 'Frankish Europe', 'Aachen,Frankfurt,Rome', 'emperor', 'schools,manuscripts,architecture,church reform,liturgical culture', 'high', 1, 'sol,jupiter,capricorn', 'Solar imperial renewal fixed into schools, script, and palace chapel.', 'Carolingian rulership joined conquest, church reform, palace learning, manuscript correction, and monumental architecture into a durable model of western imperial patronage.', 'Scriptorium management; palace school; reform edicts; Aachen chapel as monument card.', 'candidate', 'high', 'met-heilbrunn; cambridge-histories', NULL),
('patron-al-mansur-abbasid', 'al-Mansur', 'Mansur, al-', 'Abu Ja''far al-Mansur', 'Abbasid', 'male', 'c. 714-775; r. 754-775', 754, 775, 'early medieval,Abbasid', 'Iraq', 'Baghdad', 'caliph', 'urban foundation,translation,astronomy,administration', 'medium', 2, 'jupiter,mercury,earth', 'A new imperial city coagulates administration, books, and cosmic geometry.', 'The second Abbasid caliph founded Baghdad as an imperial capital and helped create the administrative and intellectual setting later associated with Abbasid translation culture.', 'City-foundation scenario; build the Round City; recruit translators and astrologers.', 'candidate', 'medium', 'cambridge-histories; specialist-monographs', NULL),
('patron-harun-al-rashid', 'Harun al-Rashid', 'Harun al-Rashid', NULL, 'Abbasid', 'male', '766-809; r. 786-809', 786, 809, 'early medieval,Abbasid', 'Iraq', 'Baghdad,Raqqa', 'caliph', 'court culture,translation,poetry,music,libraries,diplomacy', 'high', 2, 'jupiter,venus,mercury', 'Courtly magnificence and knowledge circulate through gifts, envoys, and books.', 'Harun al-Rashid became a central symbol of Abbasid court magnificence, scholarly culture, music, poetry, diplomacy, and the book-collecting environment that preceded al-Ma''mun.', 'Court festival; gift diplomacy; library expansion; musician and poet patronage.', 'candidate', 'medium', 'cambridge-histories; specialist-monographs', NULL),
('patron-al-mamun', 'al-Ma''mun', 'Ma''mun, al-', NULL, 'Abbasid', 'male', '786-833; r. 813-833', 813, 833, 'early medieval,Abbasid', 'Iraq', 'Baghdad,Merv', 'caliph', 'translation,astronomy,philosophy,mathematics,libraries', 'high', 1, 'mercury,jupiter,cancer', 'Mercurial translation under Jovian rule conjoins Greek, Syriac, Persian, Indian, and Arabic traditions.', 'al-Ma''mun is a central patron of Abbasid translation, astronomy, disputation, and manuscript acquisition, though the institutional myth of a single House of Wisdom requires careful handling.', 'Translation-engine patron; acquire manuscripts; sponsor observations; manage theological risk.', 'sourced', 'critical', 'specialist-monographs; cambridge-histories', 'Use Dimitri Gutas and recent House of Wisdom historiography.'),
('patron-basil-i', 'Basil I', 'Basil I', NULL, 'Macedonian', 'male', '811-886; r. 867-886', 867, 886, 'middle Byzantine,Macedonian Renaissance', 'Byzantium', 'Constantinople', 'emperor', 'architecture,manuscripts,church art,imperial ideology', 'medium', 3, 'sol,jupiter,capricorn', 'Imperial restoration fixed through churches, books, and ceremonial image.', 'Basil I and the Macedonian court helped shape the revival of Byzantine art, classicizing manuscript culture, imperial ceremonial, and church patronage.', 'Byzantine palace ceremony; church mosaic; manuscript revival.', 'candidate', 'medium', 'met-heilbrunn; specialist-monographs', NULL),
('patron-constantine-vii', 'Constantine VII Porphyrogennetos', 'Constantine VII Porphyrogennetos', NULL, 'Macedonian', 'male', '905-959; r. 913-959', 913, 959, 'middle Byzantine,Macedonian Renaissance', 'Byzantium', 'Constantinople', 'emperor-scholar', 'encyclopedism,manuscripts,ceremony,historiography', 'high', 2, 'mercury,saturn,jupiter', 'The emperor preserves knowledge as ceremonial memory and political order.', 'Constantine VII is the exemplary Byzantine scholar-emperor, associated with encyclopedic compilations, court ceremony, imperial history, and learned preservation.', 'Compile court manuals; classify provinces; diplomatic knowledge mechanic.', 'candidate', 'high', 'met-heilbrunn; specialist-monographs', NULL),
('patron-abd-al-rahman-iii', 'Abd al-Rahman III', 'Abd al-Rahman III', NULL, 'Umayyad of Cordoba', 'male', '891-961; r. 912-961', 912, 961, 'medieval,al-Andalus', 'Iberia', 'Cordoba,Madinat al-Zahra', 'caliph', 'architecture,libraries,urbanism,court luxury,diplomacy', 'high', 2, 'sol,jupiter,earth', 'A solar caliphate materializes in palaces, libraries, and diplomatic spectacle.', 'Abd al-Rahman III proclaimed the Cordoban caliphate and sponsored palace-city construction, court magnificence, libraries, and diplomatic display at Madinat al-Zahra.', 'Build palace-city; receive embassies; library prestige; material luxury economy.', 'candidate', 'high', 'met-heilbrunn; specialist-monographs', NULL),
('patron-al-hakam-ii', 'al-Hakam II', 'Hakam II, al-', NULL, 'Umayyad of Cordoba', 'male', '915-976; r. 961-976', 961, 976, 'medieval,al-Andalus', 'Iberia', 'Cordoba', 'caliph', 'libraries,books,scholarship,translation,mosque architecture', 'high', 1, 'mercury,saturn,jupiter', 'A library caliph: knowledge collected, copied, and fixed into prestige.', 'al-Hakam II is famous for book collecting, scholarly patronage, and the intellectual prestige of Cordoba, including expansion and embellishment of major religious architecture.', 'Library acquisition market; copyists and agents; book catalog minigame.', 'candidate', 'high', 'cambridge-histories; specialist-monographs', NULL),
('patron-mahmud-ghazni', 'Mahmud of Ghazni', 'Mahmud of Ghazni', NULL, 'Ghaznavid', 'male', '971-1030; r. 998-1030', 998, 1030, 'medieval,Persianate', 'Afghanistan,Iran,North India', 'Ghazni', 'sultan', 'poetry,Persian literature,architecture,court culture,conquest display', 'high', 2, 'mars,jupiter,venus', 'Martial conquest feeds Persianate literary magnificence.', 'Mahmud of Ghazni made conquest revenue and courtly Persian culture mutually reinforcing, patronizing poets, scholars, architecture, and a prestigious Ghaznavid court.', 'Raid-to-court economy; poet patronage; legitimacy through panegyric.', 'candidate', 'medium', 'cambridge-histories; specialist-monographs', NULL),
('patron-nizam-al-mulk', 'Nizam al-Mulk', 'Nizam al-Mulk', 'Abu Ali Hasan ibn Ali Tusi', 'Seljuk administration', 'male', '1018-1092', 1060, 1092, 'medieval,Seljuk', 'Iran,Iraq', 'Isfahan,Baghdad,Nishapur', 'vizier', 'madrasas,scholarship,administration,law,political thought', 'high', 2, 'jupiter,salt,capricorn', 'Institutions fix doctrine, law, and administrative continuity.', 'The Seljuk vizier Nizam al-Mulk sponsored the Nizamiyya madrasas and became a model for institutional patronage of scholarship, law, and political administration.', 'Madrasa network; appoint professors; doctrinal rivalry; bureaucracy card.', 'candidate', 'high', 'cambridge-histories; specialist-monographs', NULL),
('patron-roger-ii-sicily', 'Roger II of Sicily', 'Roger II of Sicily', NULL, 'Hauteville', 'male', '1095-1154; r. 1130-1154', 1130, 1154, 'medieval,Norman Sicily', 'Sicily', 'Palermo', 'king', 'architecture,mosaics,geography,translation,court science,multilingual administration', 'high', 1, 'jupiter,mercury,cancer', 'Norman, Greek, Arabic, and Latin traditions conjoin in a court of maps and mosaics.', 'Roger II ruled a multilingual Mediterranean court whose patronage included palace architecture, Byzantine-style mosaics, Arabic administration, and al-Idrisi''s geographical work.', 'Map commission; multilingual court staff; palace chapel visual program.', 'candidate', 'high', 'met-heilbrunn; specialist-monographs', NULL),
('patron-eleanor-aquitaine', 'Eleanor of Aquitaine', 'Eleanor of Aquitaine', NULL, 'Poitiers/Plantagenet', 'female', 'c. 1122-1204', 1137, 1204, 'high medieval,courtly culture', 'France,England', 'Poitiers,Paris,London', 'queen,duchess', 'courtly literature,music,poetry,dynastic culture', 'medium', 2, 'venus,jupiter,luna', 'Courtly sociability and dynastic power refract through song, marriage, and memory.', 'Eleanor of Aquitaine is central to traditions of aristocratic literary and courtly patronage, though specific attributions require careful source review.', 'Troubadour network; marriage diplomacy; court reputation system.', 'candidate', 'medium', 'specialist-monographs', 'Separate documented patronage from later court-of-love legend.'),
('patron-henry-ii-england', 'Henry II of England', 'Henry II of England', NULL, 'Plantagenet', 'male', '1133-1189; r. 1154-1189', 1154, 1189, 'high medieval,Plantagenet', 'England,France', 'London,Chinon', 'king', 'law,historiography,administration,architecture', 'medium', 3, 'jupiter,salt,mars', 'Law and record-keeping coagulate royal power.', 'Henry II''s court patronage is tied to legal administration, historical writing, architecture, and the cultural infrastructure of a large Angevin realm.', 'Legal reform card; chronicler relations; castle and archive economy.', 'candidate', 'low', 'specialist-monographs', NULL),
('patron-frederick-ii-hre', 'Frederick II', 'Frederick II, Holy Roman Emperor', 'Stupor Mundi', 'Hohenstaufen', 'male', '1194-1250; r. 1220-1250', 1198, 1250, 'high medieval,imperial,Mediterranean', 'Sicily,Italy,Germany', 'Palermo,Foggia,Lucera', 'emperor', 'science,translation,falconry,law,architecture,astrology,court learning', 'high', 1, 'sol,mercury,mars', 'Imperial curiosity joins natural observation, law, and martial kingship.', 'Frederick II sponsored a multilingual Sicilian-imperial court associated with scientific curiosity, translations, law, architecture, falconry, astrology, and learned debate.', 'Court naturalist route; falconry manuscript; astrologers and translators; papal conflict.', 'candidate', 'high', 'met-heilbrunn; specialist-monographs', NULL),
('patron-blanche-castile', 'Blanche of Castile', 'Blanche of Castile', NULL, 'Capetian/Castilian', 'female', '1188-1252', 1223, 1252, 'high medieval,Capetian', 'France', 'Paris', 'queen,regent', 'manuscripts,monastic patronage,architecture,royal piety', 'high', 2, 'luna,jupiter,salt', 'Regency, piety, and dynastic memory are stabilized in books and foundations.', 'Blanche of Castile was a powerful queen-regent and religious patron, associated with manuscripts, monastic foundations, and Capetian dynastic piety.', 'Regency crisis; manuscript devotion; monastic alliance.', 'candidate', 'medium', 'met-heilbrunn; specialist-monographs', NULL),
('patron-louis-ix', 'Louis IX of France', 'Louis IX of France', 'Saint Louis', 'Capetian', 'male', '1214-1270; r. 1226-1270', 1226, 1270, 'high medieval,Capetian', 'France', 'Paris', 'king,saint', 'relics,architecture,manuscripts,crusade,piety,law', 'high', 1, 'sol,jupiter,capricorn', 'Sacred kingship fixes relic, law, and architecture into a royal theology.', 'Louis IX sponsored Sainte-Chapelle, relic veneration, royal justice, crusading piety, and manuscript culture, making him a central figure in Gothic royal patronage.', 'Relic acquisition; Sainte-Chapelle build; crusade-piety tension.', 'candidate', 'high', 'met-heilbrunn; specialist-monographs', NULL),
('patron-alfonso-x', 'Alfonso X of Castile', 'Alfonso X of Castile', 'Alfonso el Sabio', 'Burgundy-Ivrea', 'male', '1221-1284; r. 1252-1284', 1252, 1284, 'high medieval,Iberian', 'Castile-Leon', 'Toledo,Seville', 'king', 'astronomy,translation,law,music,history,vernacular science', 'high', 1, 'mercury,jupiter,aquarius', 'Royal patronage multiplies Arabic, Jewish, Christian, Castilian, and Latin knowledge traditions.', 'Alfonso X sponsored astronomical, legal, historical, musical, and translational projects, making his court one of medieval Europe''s richest knowledge engines.', 'Translation lab; Alfonsine Tables; vernacular science; court musicians.', 'sourced', 'critical', 'loc; ismi; alfa', NULL),
('patron-james-i-aragon', 'James I of Aragon', 'James I of Aragon', 'Jaume I', 'Barcelona', 'male', '1208-1276; r. 1213-1276', 1213, 1276, 'high medieval,Iberian', 'Aragon,Catalonia,Valencia,Majorca', 'Barcelona,Valencia,Majorca', 'king', 'chronicle,law,urban foundations,conquest memory', 'medium', 3, 'mars,jupiter,salt', 'Conquest becomes law, city, and memory.', 'James I''s reign generated conquest narratives, legal ordering, urban foundations, and Mediterranean royal identity in the Crown of Aragon.', 'Conquest chronicle; city charter; maritime expansion.', 'candidate', 'low', 'specialist-monographs', NULL),
('patron-ladislaus-iv-kuman', 'Bela IV of Hungary', 'Bela IV of Hungary', NULL, 'Arpad', 'male', '1206-1270; r. 1235-1270', 1235, 1270, 'high medieval,Hungarian', 'Hungary', 'Buda,Esztergom', 'king', 'urban foundations,fortifications,church patronage,reconstruction', 'medium', 3, 'earth,saturn,jupiter', 'After devastation, patronage fixes stone, towns, and memory.', 'Bela IV rebuilt Hungary after the Mongol invasion through fortification, settlement policy, urban privileges, and religious patronage.', 'Post-invasion reconstruction; castle building; town privileges.', 'candidate', 'low', 'specialist-monographs', 'ID uses older placeholder spelling; keep display name authoritative.'),
('patron-dinis-portugal', 'Dinis of Portugal', 'Dinis of Portugal', 'King Dinis; Dom Dinis', 'Burgundy Portugal', 'male', '1261-1325; r. 1279-1325', 1279, 1325, 'late medieval,Iberian', 'Portugal', 'Lisbon,Coimbra', 'king', 'poetry,universities,law,agriculture,language', 'high', 2, 'venus,jupiter,earth', 'Poetry, law, land, and language are cultivated together.', 'Dinis of Portugal patronized troubadour poetry, founded or supported institutions of learning, promoted Portuguese administration, and linked kingship to cultivation and law.', 'Poet-king; university foundation; agricultural development.', 'candidate', 'medium', 'specialist-monographs', NULL),
('patron-robert-anjou', 'Robert of Anjou', 'Robert of Anjou', 'Robert the Wise', 'Angevin Naples', 'male', '1277-1343; r. 1309-1343', 1309, 1343, 'late medieval,Angevin', 'Naples,Provence', 'Naples,Avignon', 'king', 'humanism,poetry,painting,scholastic culture,court ceremony', 'high', 2, 'jupiter,mercury,venus', 'A learned royal court makes wisdom a dynastic style.', 'Robert of Anjou was praised as a learned king and patron of letters, theology, painting, and court culture in Angevin Naples.', 'Court disputation; poet patronage; royal wisdom propaganda.', 'candidate', 'medium', 'met-heilbrunn; specialist-monographs', NULL),
('patron-castruccio-castracani', 'Castruccio Castracani', 'Castruccio Castracani', NULL, 'Antelminelli', 'male', '1281-1328', 1316, 1328, 'late medieval,Italian city-states', 'Italy', 'Lucca', 'lord,condottiere', 'urban power,fortification,courtly image', 'medium', 4, 'mars,jupiter,earth', 'Military lordship seeks permanence through walls and civic image.', 'Castruccio is a lower-tier but useful Italian lord-patron candidate for fortification, court image, and military power in Tuscan politics.', 'Condottiere mini-faction; fortification and legitimacy.', 'candidate', 'low', 'specialist-monographs', NULL),
('patron-charles-v-france', 'Charles V of France', 'Charles V of France', 'Charles the Wise', 'Valois', 'male', '1338-1380; r. 1364-1380', 1364, 1380, 'late medieval,Valois', 'France', 'Paris,Vincennes,Louvre', 'king', 'libraries,translation,architecture,historiography,royal image', 'high', 1, 'jupiter,saturn,capricorn', 'Royal wisdom is fixed into libraries, translations, buildings, and images.', 'Charles V rebuilt Valois authority through architecture, royal libraries, translation, political writing, and dynastic representation.', 'Royal library; translation policy; rebuild after war; Louvre knowledge hub.', 'candidate', 'high', 'met-heilbrunn', NULL),
('patron-jean-de-berry', 'Jean, duc de Berry', 'Jean, duc de Berry', 'John, Duke of Berry', 'Valois', 'male', '1340-1416', 1360, 1416, 'late medieval,Valois,International Gothic', 'France', 'Bourges,Paris,Poitiers', 'duke', 'manuscripts,jewels,devotional art,tombs,collecting', 'high', 1, 'luna,saturn,capricorn', 'Sacred time and aristocratic memory are fixed in illuminated books and treasure.', 'Jean de Berry was one of the greatest late medieval patrons of manuscripts, jewels, tomb sculpture, and devotional luxury, especially through the fame of the Tres Riches Heures.', 'Book of hours production; pigment economy; calendar board mode.', 'sourced', 'critical', 'met-heilbrunn', NULL),
('patron-philip-bold-burgundy', 'Philip the Bold', 'Philip the Bold, Duke of Burgundy', NULL, 'Valois Burgundy', 'male', '1342-1404', 1363, 1404, 'late medieval,Burgundian', 'Burgundy,Low Countries', 'Dijon,Champmol', 'duke', 'monastic foundation,tombs,sculpture,manuscripts,dynastic memory', 'high', 1, 'mars,saturn,capricorn', 'Dynastic memory is carved from martial power into mourning stone.', 'Philip the Bold founded the Burgundian Valois court style through Champmol, tomb sculpture, religious foundations, and luxury patronage.', 'Chartreuse de Champmol; pleurants; dynastic tomb commission.', 'candidate', 'high', 'met-heilbrunn', NULL),
('patron-margaret-iii-flanders', 'Margaret III of Flanders', 'Margaret III of Flanders', 'Marguerite of Male', 'Flanders/Burgundy', 'female', '1350-1405', 1384, 1405, 'late medieval,Burgundian', 'Flanders,Burgundy', 'Lille,Ghent,Dijon', 'countess,duchess', 'dynastic patronage,textiles,urban wealth,religious gifts', 'medium', 3, 'venus,jupiter,earth', 'Marriage and inheritance conjoin textile wealth with Burgundian magnificence.', 'Margaret III brought Flanders into Burgundian power and is a useful patronage node for textile wealth, marriage politics, and religious/dynastic display.', 'Marriage inheritance; textile economy; Burgundian expansion.', 'candidate', 'low', 'specialist-monographs', NULL),
('patron-isabeau-bavaria', 'Isabeau of Bavaria', 'Isabeau of Bavaria', 'Isabeau de Baviere', 'Wittelsbach/Valois', 'female', 'c. 1370-1435', 1385, 1435, 'late medieval,Valois', 'France', 'Paris', 'queen', 'manuscripts,jewels,fashion,diplomacy,royal image', 'medium', 3, 'luna,venus,jupiter', 'Queenship reflects and distorts royal legitimacy in a fractured court.', 'Isabeau of Bavaria is a significant but politically contested queen-patron tied to manuscripts, jewels, fashion, diplomacy, and Valois crisis imagery.', 'Factional court; queenly image; propaganda danger.', 'candidate', 'low', 'specialist-monographs', 'Requires careful historiography because of hostile sources.'),
('patron-henry-iv-england', 'Henry IV of England', 'Henry IV of England', NULL, 'Lancaster', 'male', '1367-1413; r. 1399-1413', 1399, 1413, 'late medieval,Lancastrian', 'England', 'London', 'king', 'royal image,manuscripts,chapel,legitimacy', 'medium', 3, 'mars,jupiter,saturn', 'Usurpation seeks legitimacy through piety, lineage, and royal image.', 'Henry IV is useful as a patronage case of post-usurpation legitimacy, court culture, manuscript display, and Lancastrian dynastic memory.', 'Legitimacy tracker; chapel patronage; rebellion pressure.', 'candidate', 'low', 'specialist-monographs', NULL),
